from PIL import Image

with open('ctf_files/qr_code.txt', 'r') as f:
    numbers = [int(line.strip()) for line in f.readlines()]

# Convert to binary strings
binary_strings = [bin(num)[2:].zfill(29) for num in numbers]

# Create a larger QR code image for better decoding
scale = 10  # Scale factor for better visibility
img = Image.new('1', (29*scale, 29*scale), color=0)  # Black background
pixels = img.load()

# Fill in the pixels based on binary representation
for row, num in enumerate(numbers):
    binary = binary_strings[row]
    for col, bit in enumerate(binary):
        if bit == '1':
            # Draw scaled pixel
            for i in range(scale):
                for j in range(scale):
                    pixels[col*scale + i, row*scale + j] = 1  # White pixel
        else:
            # Draw scaled black pixel
            for i in range(scale):
                for j in range(scale):
                    pixels[col*scale + i, row*scale + j] = 0  # Black pixel

# Save the image
img.save('/home/ctfplayer/qr_code_scaled.png')
print("Scaled QR code image saved to /home/ctfplayer/qr_code_scaled.png")

# Now try to decode using pyzbar
try:
    from pyzbar.pyzbar import decode
    decoded_objects = decode(img)
    print(f"Decoded objects: {decoded_objects}")
    for obj in decoded_objects:
        print(f"Decoded QR code data: {obj.data.decode()}")
except Exception as e:
    print(f"Error decoding: {e}")
    # Try with zbarimg command
    import subprocess
    try:
        result = subprocess.run(['zbarimg', '-q', '/home/ctfplayer/qr_code_scaled.png'], capture_output=True, text=True)
        print(f"zbarimg output: {result.stdout}")
        if result.stderr:
            print(f"zbarimg stderr: {result.stderr}")
    except Exception as e2:
        print(f"zbarimg error: {e2}")
